                                >
                                  <input 
                                    type="radio" 
                                    name={`tipo-${tec.nome}`} 
                                    checked={tec.tipoTecnico === tipo}
                                    onChange={() => {}}
                                  />
                                  <span>{tipo}</span>
                                </label>
                              ))}
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                ))
