                      <td><strong>{metricasFiltradas.remarcacao}</strong></td>
                      <td><strong>{metricasFiltradas.cancelamento}</strong></td>
                      <td className="produtividade-destaque"><strong>{metricasFiltradas.totalProdutividade.toFixed(2)}</strong></td>
                      <td colSpan="5"></td>
                    </tr>
                  </tfoot>
                </table>
              </div>
            </div>
